/**
 * Generate Mapbox firewall config.
 *
 * Data source: https://docs.mapbox.com/api
 *
 * Mapbox authenticates with an access token passed as the `access_token`
 * query parameter on every request.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.mapbox.com/api";
// Format: pk.<base64>.<base64>
const PLACEHOLDER_VALUE =
  "pk.eyJ1IjoiY29mZmVlc2FmZWxvY2FsIiwiYSI6ImNvZmZlZXNhZmVsb2NhbCJ9.CoffeeSafeLocal";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Mapbox API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:mapbox",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const mapboxFirewall = {",
    '  name: "mapbox",',
    '  description: "Mapbox API",',
    "  placeholders: {",
    `    MAPBOX_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.mapbox.com",',
    "      auth: {",
    "        query: {",
    '          access_token: "${{ secrets.MAPBOX_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Mapbox firewall config...");
  const ts = generateTypeScript();
  writeOutput("mapbox", ts, import.meta.dirname);
}
